final:
module RefModule (
  input clk,
  input clear,
  input en,
  output reg [2:0] count,
  output carry
);always @(posedge clk) begin
	if (clear) begin
		count <= 3'b000;
	end else if (en) begin
		count <= count + 1;
	end
end

  wire _n01 = count[0] ^ 3'b111[0];
  wire _n02 = count[1] ^ 3'b111[1];
  wire _n03 = count[2] ^ 3'b111[2];
  wire _n04 = count[3] ^ 3'b111[3];
  assign carry = ~_n01 & ~_n02 & ~_n03 & ~_n04;

endmodule
